const express = require('express');
const axios = require('axios');

const app = express();
const PORT = 3000;

// Middleware to parse JSON bodies
app.use(express.json());

// POST /verify-nin endpoint
app.post('/verify-nin', async (req, res, next) => {
  try {
    const { number } = req.body;

    // Validate that number is provided
    if (!number) {
      return res.status(400).json({
        error: true,
        message: 'Validation failed',
        details: 'number field is required'
      });
    }

    // Call Prembly NIN verification API
    const premblyResponse = await axios.post(
      'https://api.prembly.com/verification/nin',
      { number },
      {
        headers: {
          'app-id': process.env.PREMBLY_APP_ID,
          'x-api-key': process.env.PREMBLY_API_KEY,
          'Content-Type': 'application/json'
        }
      }
    );

    // Return successful response
    return res.status(200).json(premblyResponse.data);
  } catch (error) {
    // Pass the error to the error handling middleware
    next(error);
  }
});

// Global error handling middleware
app.use((err, req, res, next) => {
  // Extract error message from the error
  let errorMessage = 'An unknown error occurred';

  if (err.response) {
    // The request was made and the server responded with a status code
    // that falls out of the range of 2xx
    errorMessage = err.response.data?.message || err.response.data?.error || err.message;
  } else if (err.request) {
    // The request was made but no response was received
    errorMessage = 'No response received from Prembly API';
  } else {
    // Something happened in setting up the request that triggered an Error
    errorMessage = err.message;
  }

  // Return normalized error response
  res.status(400).json({
    error: true,
    message: 'Verification failed',
    details: errorMessage
  });
});

// Start the server
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

